// Solution
class Solution {
  public int findFirstDuplicate(int[] nums) {
    java.util.HashSet<Integer> seen = new java.util.HashSet<>();
    for (int num : nums) {
      if (seen.contains(num)) {
        return num;
      }
      seen.add(num);
    }
    return -1;
  }
}
